import React from 'react';
import { Clear } from '@mui/icons-material';
import styled from '@emotion/styled';


const X = styled(Clear)(() => ({
    position: 'absolute',
    right: '0px',
    top: '0px',
    color: 'white',
    backgroundColor: 'darkgray',
    display: 'inline-block',
    zIndex: 100000,
    width: '20px',
    height: '20px',
    transform: 'scale(1)',
    transition: 'all .25s ease-in-out',
    borderRadius: '50%',
    marginRight: '5%',
    marginTop: '5%',
    '&:hover': {
        transform: 'scale(1.5)'
    }
}))

const Preview = styled('div')(() => ({
    // padding: '0.5rem',
    width: '20%',
    maxHeight: '150px',
    marginRight: '1vw',
    display: 'flex',
    alignContent: 'center',
    justifyContent: 'center',
    position: 'relative',
    cursor: 'pointer',
    overflow: 'hidden',
    borderRadius: '10px',
    "&:hover #deletebutton": {
    }
}))

export default React.memo(function ImageUploadThumbnail(props) {
    const { url, id, removeFile } = props

    const handleRemove = (e) => {
        e.stopPropagation();
        removeFile(id)
    }

    return (
        <>
            <Preview id='mydiv' style={{ backgroundImage: url }}
            >
                <X id='deletebutton' onClick={handleRemove} />
                <img alt='' id={id} src={url} style={{
                    flexShrink: 0,
                    height: '100%', width: '100%', objectFit: 'cover'
                }} />
            </Preview>
        </>
    )
})